#[test]
fn test_kpoints_mp_offset_from_cell_value() {
    let val = CellValue::Array(vec![
        CellValue::Float(0.25),
        CellValue::Float(0.25),
        CellValue::Float(0.25),
    ]);
    let offset = KpointsMpOffset::from_cell_value(&val).unwrap();
    assert_eq!(offset.0, [0.25, 0.25, 0.25]);
}

#[test]
fn test_symmetry_generate_to_cell() {
    let sg = SymmetryGenerate;
    let cell = sg.to_cell();
    match cell {
        Cell::Flag(name) => assert_eq!(name, "SYMMETRY_GENERATE"),
        _ => panic!("Expected Cell::Flag, got {:?}", cell),
    }
}
